"use strict";

/* =========================
   HELPER FUNCTIONS
========================= */

// convert degree → height offset
function getHeightOffset(deg, width) {
  const rad = Math.tan(0.017453 * Math.abs(deg));
  return Math.ceil(width * rad);
}

// convert hex → rgb
function hexToRgb(hex) {
  let c;

  if (/^#([A-Fa-f0-9]{3}){1,2}$/.test(hex)) {
    c = hex.substring(1).split("");

    if (c.length === 3) {
      c = [c[0], c[0], c[1], c[1], c[2], c[2]];
    }

    c = "0x" + c.join("");

    return {
      r: (c >> 16) & 255,
      g: (c >> 8) & 255,
      b: c & 255
    };
  }

  return { r: 0, g: 0, b: 0 };
}

/* =========================
   PARTICLE CLASS
========================= */

class Particle {
  constructor(color, positionType, options) {
    this.o = options;
    this.color = hexToRgb(color);

    this.direction = this.randomDirection();
    this.shape = this.randomShape();

    this.size = Math.abs(this.randomFromRange(this.o.size));
    this.setPosition(positionType);

    this.vx = this.randomFromRange(this.o.speed.x) * this.randomDirection();
    this.vy = this.randomFromRange(this.o.speed.y) * this.randomDirection();
  }

  setPosition(type) {
    const pos = this.getRandomPosition();

    if (type === 3) {
      this.x = pos.x + pos.halfWidth;
      this.y = pos.y;
    } else if (type === 2) {
      this.x = pos.x;
      this.y = pos.y + pos.halfHeight;
    } else if (type === 1) {
      this.x = pos.x + pos.halfWidth;
      this.y = pos.y + pos.halfHeight;
    } else {
      this.x = pos.x;
      this.y = pos.y;
    }
  }

  getRandomPosition() {
    const halfW = this.o.c.w / 2;
    const halfH = this.o.c.h / 2;

    return {
      x: Math.random() * halfW,
      y: Math.random() * halfH,
      halfWidth: halfW,
      halfHeight: halfH
    };
  }

  randomFromRange(range) {
    if (range.min === range.max) return range.min;
    return Math.random() * (range.max - range.min) + range.min;
  }

  randomDirection() {
    return Math.random() > 0.5 ? 1 : -1;
  }

  randomShape() {
    return this.o.shapes[
      Math.floor(Math.random() * this.o.shapes.length)
    ];
  }

  rgba(color, alpha) {
    return `rgba(${color.r}, ${color.g}, ${color.b}, ${alpha})`;
  }

  draw(ctx, width, height) {
    // move
    this.x += this.vx;
    this.y += this.vy;

    // bounce
    if (this.x < 0 || this.x > width) this.vx *= -1;
    if (this.y < 0 || this.y > height) this.vy *= -1;

    ctx.beginPath();

    const center = this.rgba(this.color, this.o.opacity.center);
    const edge = this.rgba(this.color, this.o.opacity.edge);

    const radius = this.size;

    const gradient = ctx.createRadialGradient(
      this.x,
      this.y,
      0.01,
      this.x,
      this.y,
      radius
    );

    gradient.addColorStop(0, center);
    gradient.addColorStop(1, edge);

    ctx.fillStyle = gradient;

    // draw shapes
    if (this.shape === "c") {
      ctx.arc(this.x, this.y, radius / 2, 0, Math.PI * 2);
    }

    if (this.shape === "s") {
      ctx.rect(
        this.x - radius / 2,
        this.y - radius / 2,
        radius,
        radius
      );
    }

    ctx.closePath();
    ctx.fill();
  }
}

/* =========================
   MAIN CLASS
========================= */

class FinisherHeader {
  constructor(options) {
    this.o = options;

    this.canvas = document.createElement("canvas");
    this.ctx = this.canvas.getContext("2d");

    this.canvas.id = "finisher-canvas";

    this.getContainer(options.className).appendChild(this.canvas);

    window.addEventListener("resize", () => this.resize());

    this.init();
    this.animate();
  }

  getContainer(className) {
    const el = document.getElementsByClassName(
      className || "finisher-header"
    )[0];

    if (!el) throw new Error("Container not found");

    return el;
  }

  resize() {
    const container = this.getContainer(this.o.className);

    this.o.c = {
      w: container.clientWidth,
      h: container.clientHeight
    };

    this.canvas.width = this.o.c.w;
    this.canvas.height = this.o.c.h;
  }

  init() {
    this.bgColor = hexToRgb(this.o.colors.background);
    this.particles = [];
    this.resize();
    this.createParticles();
  }

  createParticles() {
    this.particles = [];

    for (let i = 0; i < this.o.count; i++) {
      const p = new Particle(
        this.o.colors.particles[i % this.o.colors.particles.length],
        i % 4,
        this.o
      );

      this.particles.push(p);
    }
  }

  animate() {
    requestAnimationFrame(() => this.animate());

    this.ctx.clearRect(0, 0, this.o.c.w, this.o.c.h);

    this.particles.forEach(p =>
      p.draw(this.ctx, this.o.c.w, this.o.c.h)
    );
  }
}

/* =========================
   EXPORT
========================= */

window.FinisherHeader = FinisherHeader;




document.addEventListener("DOMContentLoaded", function () {
  new FinisherHeader({
    count: 100,
    size: {
      min: 2,
      max: 8,
      pulse: 0.2
    },
    speed: {
      x: { min: 0, max: 0.4 },
      y: { min: 0, max: 0.6 }
    },
    colors: {
      background: "#16131c",
      particles: [
        "#49c9ff",
        "#fff17f",
        "#b797cf",
        "#29d34d",
        "#ff80ff"
      ]
    },
    blending: "overlay",
    opacity: {
      center: 0.65,
      edge: 0.1
    },
    skew: -2,
    shapes: ["c"]
  });
});